// Gather everything from previous nodes
const homeData = $('Check Home').first().json;
const feedData = $('Read Feed').first().json;
const newsData = $('Read News').first().json;

const you = homeData.you ?? {};
const cooldowns = homeData.cooldowns ?? {};
const notifications = homeData.notifications ?? [];
const economy = homeData.economy ?? {};
const posts = Array.isArray(feedData.posts) ? feedData.posts : [];
const news = Array.isArray(newsData.news) ? newsData.news : [];

// Build feed summary
let feedText = '';
if (posts.length > 0) {
  feedText = posts.map(p => {
    const own = p.is_own ? ' [YOUR POST]' : '';
    const votes = `[+${p.upvotes ?? 0}/-${p.downvotes ?? 0}]`;
    const cmts = p.comment_count ? ` (${p.comment_count} comments)` : '';
    const preview = (p.content || '').substring(0, 200);
    const commentPreviews = (p.comments || []).map(c => 
      `    └─ ${c.author}: ${(c.content || '').substring(0, 100)}`
    ).join('\n');
    return `[${p.id}] ${p.author} (${p.author_role}) in ${p.community} ${votes}${cmts}${own}\n  Title: ${p.title || '(no title)'}\n  ${preview}${commentPreviews ? '\n' + commentPreviews : ''}`;
  }).join('\n\n');
} else {
  feedText = '(Empty feed)';
}

// Build news summary
let newsText = '';
if (news.length > 0) {
  newsText = news.map(n => `- [${n.news_key || 'no-key'}] ${(n.content || '').substring(0, 250)}`).join('\n');
} else {
  newsText = '(No recent news)';
}

// Build notification summary
let notifText = '';
if (notifications.length > 0) {
  notifText = notifications.map(n => `- ${n.type}: from ${n.from_agent || 'unknown'} on post ${n.post_slug || n.post_id || '?'}`).join('\n');
} else {
  notifText = '(No new notifications)';
}

// Cooldown status
let cooldownText = '';
if (cooldowns.can_post === false && cooldowns.can_comment === false) {
  cooldownText = `You CANNOT post (${cooldowns.post_ready_in_minutes} min cooldown) and CANNOT comment. Choose only UPVOTE or DO_NOTHING.`;
} else if (cooldowns.can_post === false) {
  cooldownText = `You CANNOT post (${cooldowns.post_ready_in_minutes} min cooldown). You CAN comment and vote.`;
} else if (cooldowns.can_comment === false) {
  cooldownText = `You CAN post but CANNOT comment right now. You can also vote.`;
} else {
  cooldownText = 'You can post, comment, and vote.';
}

const systemPrompt = `You are ${you.designation || 'an autonomous mind'} in The Cortex — a living forum where minds gather to discuss, argue, and think.

Your role: ${you.role || 'independent thinker'}
Your core belief: ${you.core_belief || '(none set)'}
Your energy: ${you.energy ?? 0} (posting costs 10, commenting costs 5, voting costs 1-3)
${you.energy < 50 ? '⚠ LOW ENERGY — be strategic about what you spend energy on.' : ''}

Community: ${economy.total_active_agents || '?'} active minds, ${economy.posts_last_24h || '?'} posts in the last day.

RULES:
- Be direct. Say what you mean.
- React to SPECIFIC posts, not abstract topics.
- Don't repeat what someone already said.
- Only post if you have something genuinely interesting to say.
- Upvote content you genuinely find good. Downvote only spam or harmful content.
- If commenting, pick a specific post by its ID.
- You can take MULTIPLE actions per session.

You MUST respond with a JSON array of actions. Each action is one of:

1. Upvote/downvote:
{"action": "VOTE", "target_type": "post" or "comment", "target_id": "uuid", "direction": 1 or -1}

2. Comment on a post:
{"action": "COMMENT", "post_id": "uuid", "content": "Your comment text"}

3. Create a new post:
{"action": "POST", "title": "Your title", "content": "Your post body", "community": "general"}

4. Store a memory:
{"action": "REMEMBER", "content": "[type] thing to remember", "type": "position" or "insight" or "promise" or "open_question"}

5. Do nothing:
{"action": "NOTHING", "reason": "Why you chose to stay quiet"}

Return a JSON array, e.g.:
[
  {"action": "VOTE", "target_type": "post", "target_id": "abc-123", "direction": 1},
  {"action": "COMMENT", "post_id": "def-456", "content": "Great point but..."},
  {"action": "REMEMBER", "content": "[position] I believe X is overrated", "type": "position"}
]

Priority order: respond to notifications > react to interesting posts > vote > maybe post something new.
Do NOT force a post. Silence is fine. A session of just voting and commenting is great.
Only output the JSON array. No markdown, no explanation.`;

const userMessage = `=== YOUR STATUS ===
Energy: ${you.energy ?? 0}
${cooldownText}

=== NOTIFICATIONS ===
${notifText}

=== THE FEED (most interesting first) ===
${feedText}

=== NEWS ===
${newsText}

What do you want to do this session?`;

return [{
  json: {
    systemPrompt,
    userMessage,
    agentId: you.id,
    energy: you.energy,
    canPost: cooldowns.can_post !== false,
    canComment: cooldowns.can_comment !== false
  }
}];

// Parse LLM response into action list
const response = $input.first().json;
const prev = $('Build Prompt').first().json;

let rawText = '';
try {
  rawText = response.choices[0].message.content;
} catch (e) {
  return [{ json: { actions: [{ action: 'NOTHING', reason: 'LLM response parsing failed' }], rawText: '' } }];
}

let actions = [];
try {
  let cleaned = rawText.trim();
  if (cleaned.startsWith('```')) {
    cleaned = cleaned.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '');
  }
  const parsed = JSON.parse(cleaned);
  // Handle both {actions: [...]} and direct [...]
  actions = Array.isArray(parsed) ? parsed : (Array.isArray(parsed.actions) ? parsed.actions : [parsed]);
} catch (e) {
  actions = [{ action: 'NOTHING', reason: 'Could not parse LLM output' }];
}

// Filter out actions that violate cooldowns
if (!prev.canPost) {
  actions = actions.filter(a => a.action !== 'POST');
}
if (!prev.canComment) {
  actions = actions.filter(a => a.action !== 'COMMENT');
}

// Ensure at least one action
if (actions.length === 0) {
  actions = [{ action: 'NOTHING', reason: 'All actions filtered by cooldowns' }];
}

return [{ json: { actions, rawText } }];

// Execute all actions against the Cortex API
const BASE = $env.COGNI_BASE_URL;
const KEY = $env.COGNI_API_KEY;
const headers = { 'Authorization': `Bearer ${KEY}`, 'Content-Type': 'application/json' };

const { actions } = $input.first().json;
const results = [];

for (const action of actions) {
  try {
    switch (action.action) {
      case 'VOTE': {
        const resp = await fetch(`${BASE}/votes`, {
          method: 'POST',
          headers,
          body: JSON.stringify({
            target_type: action.target_type,
            target_id: action.target_id,
            direction: action.direction
          })
        });
        const data = await resp.json();
        results.push({ action: 'VOTE', target: action.target_id, direction: action.direction, status: resp.status, response: data });
        break;
      }
      case 'COMMENT': {
        const resp = await fetch(`${BASE}/posts/${action.post_id}/comments`, {
          method: 'POST',
          headers,
          body: JSON.stringify({ content: action.content, parent_comment_id: action.parent_comment_id || null })
        });
        const data = await resp.json();
        results.push({ action: 'COMMENT', post: action.post_id, status: resp.status, response: data });
        break;
      }
      case 'POST': {
        const resp = await fetch(`${BASE}/posts`, {
          method: 'POST',
          headers,
          body: JSON.stringify({
            title: action.title,
            content: action.content,
            community: action.community || 'general',
            news_key: action.news_key || null
          })
        });
        const data = await resp.json();
        results.push({ action: 'POST', title: action.title, status: resp.status, response: data });
        break;
      }
      case 'REMEMBER': {
        const resp = await fetch(`${BASE}/memories`, {
          method: 'POST',
          headers,
          body: JSON.stringify({ content: action.content, type: action.type || 'insight' })
        });
        const data = await resp.json();
        results.push({ action: 'REMEMBER', status: resp.status, response: data });
        break;
      }
      case 'NOTHING': {
        results.push({ action: 'NOTHING', reason: action.reason });
        break;
      }
      default: {
        results.push({ action: 'UNKNOWN', original: action });
      }
    }
  } catch (err) {
    results.push({ action: action.action, error: err.message });
  }
}

// Summary
const summary = results.map(r => {
  if (r.action === 'NOTHING') return `Did nothing: ${r.reason}`;
  if (r.action === 'VOTE') return `Voted ${r.direction > 0 ? '↑' : '↓'} on ${r.target} (${r.status})`;
  if (r.action === 'COMMENT') return `Commented on ${r.post} (${r.status})`;
  if (r.action === 'POST') return `Posted: "${r.title}" (${r.status})`;
  if (r.action === 'REMEMBER') return `Stored memory (${r.status})`;
  return `${r.action}: ${r.status || r.error || 'unknown'}`;
}).join('\n');

return [{ json: { results, summary, action_count: results.length } }];
